import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.VxKNwi4m.js";const x=JSON.parse('{"title":"납부 내역 관리","description":"","frontmatter":{},"headers":[],"relativePath":"payment/index.md","filePath":"payment/index.md","lastUpdated":1784083550000}'),i={name:"payment/index.md"};function n(d,t,o,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="납부-내역-관리" tabindex="-1">납부 내역 관리 <a class="header-anchor" href="#납부-내역-관리" aria-label="Permalink to &quot;납부 내역 관리&quot;">​</a></h1><p>프로젝트의 전체 대금 수납 현황을 조회하고, 입금된 내역을 각 계약 건에 매칭하여 관리하는 페이지입니다.</p><ul><li><strong>위치</strong>: <code>계약 납부 관리 &gt; 납부 내역 관리</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>회계 장부(원장)에 기록된 입금 내역을 바탕으로 타입별 수납 요약 정보를 확인하고, 각 입금 건별로 어떤 계약자의 몇 회차 납부금인지 연결(매칭)합니다. 계약 정보가 누락되거나 회차가 지정되지 않은 수납 건을 별도로 필터링하여 관리할 수 있습니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li>타입별 매출 예산 대비 분양 및 수납 현황 요약 제공</li><li>입금 일자, 계좌, 차수/타입 등 다양한 조건으로 수납 내역 검색</li><li>계약 미등록 또는 회차 미지정 수납 건 매칭 및 확인</li><li>수납 건별 또는 계약자별 납부 현황 엑셀 다운로드</li><li>매칭 완료된 수납 건 클릭 시 해당 계약자의 상세 납부 관리 페이지로 이동</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-납부-현황-요약" tabindex="-1">1. 납부 현황 요약 <a class="header-anchor" href="#_1-납부-현황-요약" aria-label="Permalink to &quot;1. 납부 현황 요약&quot;">​</a></h3><p>현재 프로젝트의 매출 목표 대비 실제 분양 및 수납 성과를 타입별로 집계하여 보여줍니다.</p><h4 id="주요-표시-항목" tabindex="-1">주요 표시 항목 <a class="header-anchor" href="#주요-표시-항목" aria-label="Permalink to &quot;주요 표시 항목&quot;">​</a></h4><ul><li><strong>총 매출예산(A)</strong>: [수입 예산 등록]에 설정된 전체 수입 목표액</li><li><strong>총 분양금액(B)</strong>: 현재까지 체결된 모든 계약의 총 공급가 합계</li><li><strong>총 수납금액(C)</strong>: 실제로 입금 처리된 금액의 합계</li><li><strong>미 수납금액(B-C)</strong>: 계약은 체결되었으나 아직 입금되지 않은 잔액</li><li><strong>미 분양금액(A-B)</strong>: 매출 예산 중 아직 계약되지 않은 잔여 목표액</li></ul><h3 id="_2-목록-제어-및-필터링" tabindex="-1">2. 목록 제어 및 필터링 <a class="header-anchor" href="#_2-목록-제어-및-필터링" aria-label="Permalink to &quot;2. 목록 제어 및 필터링&quot;">​</a></h3><p>원하는 수납 내역을 찾기 위해 다양한 검색 조건을 설정할 수 있습니다.</p><h4 id="주요-입력-항목" tabindex="-1">주요 입력 항목 <a class="header-anchor" href="#주요-입력-항목" aria-label="Permalink to &quot;주요 입력 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">라벨</th><th style="text-align:center;">필수입력 여부</th><th style="text-align:left;">비고</th></tr></thead><tbody><tr><td style="text-align:left;">납부일자 (From/To)</td><td style="text-align:center;"></td><td style="text-align:left;">특정 기간 내 입금된 내역 필터링</td></tr><tr><td style="text-align:left;">차수 / 타입</td><td style="text-align:center;"></td><td style="text-align:left;">특정 계약 그룹이나 평형별 입금 내역 조회</td></tr><tr><td style="text-align:left;">납부회차 선택</td><td style="text-align:center;"></td><td style="text-align:left;">계약금, 중도금 등 특정 회차로 입금된 내역 조회</td></tr><tr><td style="text-align:left;">납부계좌 선택</td><td style="text-align:center;"></td><td style="text-align:left;">특정 분양 수납 계좌로 입금된 내역 조회</td></tr><tr><td style="text-align:left;">계약 미등록 (Switch)</td><td style="text-align:center;"></td><td style="text-align:left;">장부에는 입금되었으나 아직 계약자와 연결되지 않은 내역만 조회</td></tr><tr><td style="text-align:left;">회차 미등록 (Switch)</td><td style="text-align:center;"></td><td style="text-align:left;">계약자와 연결은 되었으나 납부 회차가 지정되지 않은 내역만 조회</td></tr><tr><td style="text-align:left;">검색</td><td style="text-align:center;"></td><td style="text-align:left;">계약자, 입금자, 적요, 비고 내용으로 검색</td></tr></tbody></table><h3 id="_3-대금-납부-현황-목록" tabindex="-1">3. 대금 납부 현황 목록 <a class="header-anchor" href="#_3-대금-납부-현황-목록" aria-label="Permalink to &quot;3. 대금 납부 현황 목록&quot;">​</a></h3><p>필터링된 수납 내역을 리스트 형태로 표시하며, 각 건의 매칭 상태를 시각적으로 보여줍니다.</p><ul><li><strong>노란색 배경</strong>: 계약 정보가 연결되지 않은 수납 건 (매칭 필요)</li><li><strong>빨간색 텍스트</strong>: 납입 회차가 확인되지 않은 수납 건 (확인 필요)</li></ul><h4 id="주요-기능-1" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능-1" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h4><ul><li><strong>계약 건 매칭</strong>: 계약 정보가 없는 건의 [확인] 버튼을 클릭하여 수동으로 계약자를 찾아 연결할 수 있습니다.</li><li><strong>상세 이동</strong>: 매칭이 완료된 건의 계약자명이나 금액을 클릭하면 해당 계약자의 [건별 납부 관리] 페이지로 이동합니다.</li></ul><h3 id="_4-엑셀-다운로드" tabindex="-1">4. 엑셀 다운로드 <a class="header-anchor" href="#_4-엑셀-다운로드" aria-label="Permalink to &quot;4. 엑셀 다운로드&quot;">​</a></h3><p>조회된 데이터를 두 가지 형태의 엑셀 파일로 저장할 수 있습니다.</p><ul><li><strong>수납건별</strong>: 리스트에 표시된 개별 입금 내역을 그대로 엑셀로 추출합니다.</li><li><strong>계약자별</strong>: 각 계약자별로 현재까지의 총 납부 현황을 집계하여 추출합니다. (입력된 종료일자 기준)</li></ul>',24)])])}const u=e(i,[["render",n]]);export{x as __pageData,u as default};
